#include "pulse_counter.h"
#include <Arduino.h>
static uint8_t _pin=25;static volatile uint32_t _cnt=0;static float _freq=0;static uint32_t _lastCnt=0;static unsigned long _l=0;
void IRAM_ATTR _pulse_isr(){_cnt++;}
void pulse_setup(uint8_t p){_pin=p;pinMode(p,INPUT_PULLUP);attachInterrupt(p,_pulse_isr,RISING);Serial.printf("[pulse] OK pin=%d\n",p);}
void pulse_loop(){if(millis()-_l<1000)return;unsigned long dt=millis()-_l;_l=millis();_freq=(float)(_cnt-_lastCnt)*1000.0/dt;_lastCnt=_cnt;}
uint32_t pulse_get_count(){return _cnt;}
float pulse_get_frequency(){return _freq;}
void pulse_reset(){_cnt=0;_lastCnt=0;}
